class Solution:
    def findMaximumNumber(self, k: int, x: int) -> int:
        def calculate_price(num: int, x: int) -> int:
            price = 0
            i = x
            while i <= num.bit_length() * x:
                price += (num >> (i - 1)) & 1
                i += x
            return price

        def calculate_accumulated_price(num: int, x: int) -> int:
            accumulated_price = 0
            for i in range(1, num + 1):
                accumulated_price += calculate_price(i, x)
            return accumulated_price

        left, right = 1, k * 100
        while left <= right:
            mid = (left + right) // 2
            accumulated_price = calculate_accumulated_price(mid, x)
            if accumulated_price <= k:
                left = mid + 1
            else:
                right = mid - 1
        return right
